    private fun handleShareIntent(intent: Intent?) {
        if (intent == null) return

        when (intent.action) {
            Intent.ACTION_SEND -> handleSend(intent)
            Intent.ACTION_SEND_MULTIPLE -> handleSendMultiple(intent)
            else -> Log.w(TAG, "Unsupported action: ${intent.action}")
        }
    }

    private fun handleSend(intent: Intent) {
        val type = intent.type ?: return

        when {
            type == "text/plain" -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                if (!sharedText.isNullOrBlank()) {
                    processSharedUrl(sharedText)
                } else {
                    Log.w(TAG, "No shared text found")
                }
            }
            type.startsWith("image/") -> {
                val imageUri = intent.getParcelableExtraCompat<Uri>(Intent.EXTRA_STREAM)
                if (imageUri != null) {
                    processSharedImage(imageUri)
                } else {
                    Log.w(TAG, "No shared image URI found")
                }
            }
            else -> Log.w(TAG, "Unsupported MIME type: $type")
        }
    }

    private fun handleSendMultiple(intent: Intent) {
        val type = intent.type ?: return
        if (!type.startsWith("image/")) {
            Log.w(TAG, "Unsupported multiple share MIME type: $type")
            return
        }

        val imageUris = intent.getParcelableArrayListExtraCompat<Uri>(Intent.EXTRA_STREAM)
        if (imageUris.isNullOrEmpty()) {
            Log.w(TAG, "No shared image URIs found")
            return
        }

        imageUris.forEach { processSharedImage(it) }
    }

    private fun processSharedUrl(text: String) {
        Log.d(TAG, "Processing shared URL/text: $text")
    }

    private fun processSharedImage(uri: Uri) {
        contentResolver.takePersistableUriPermissionSafely(uri, intent.flags)
        Log.d(TAG, "Processing shared image URI: $uri")
    }

    private fun android.content.ContentResolver.takePersistableUriPermissionSafely(uri: Uri, intentFlags: Int) {
        val flags = intentFlags and (Intent.FLAG_GRANT_READ_URI_PERMISSION or Intent.FLAG_GRANT_WRITE_URI_PERMISSION)
        try {
            takePersistableUriPermission(uri, flags)
